  addPost: t.procedure
    .input(z.object({ title: z.string().min(5) }))
    .mutation(({ input }) => {
      return { id: 1, title: input.title };
    }),
});

const app = express();

app.use(
  express.json(),
  '/trpc',
  trpcExpress.createExpressMiddleware({
    router: appRouter,
    createContext: () => ({}),
  }),
);

app.listen(3000, () => {
  console.log('Server listening on port 3000');
});

